const HEX_R = 28; // data-space radius

// Extract points from rawData
const points = rawData.rows.map(r => [r.x, r.y]);

// --- Hexbin in data space (flat-top hexagons) ---
const axialToData = (q, r) => [
  HEX_R * 1.5 * q,
  HEX_R * Math.sqrt(3) * (r + q / 2)
];

const dataToAxialRound = (x, y) => {
  const q_f = (2/3 * x) / HEX_R;
  const r_f = (-1/3 * x + Math.sqrt(3)/3 * y) / HEX_R;
  let q = Math.round(q_f);
  let r = Math.round(r_f);
  let z = Math.round(-q_f - r_f);
  const dq = Math.abs(q - q_f), dr = Math.abs(r - r_f), dz = Math.abs(z - (-q_f - r_f));
  if (dq > dr && dq > dz) q = -r - z;
  else if (dr > dz) r = -q - z;
  return [q, r];
};

const bins = {};
points.forEach(([px, py]) => {
  const [q, r] = dataToAxialRound(px, py);
  const key = q + ',' + r;
  if (!bins[key]) bins[key] = {q, r, count: 0};
  bins[key].count++;
});

const hexData = Object.values(bins).map(b => {
  const [cx2, cy2] = axialToData(b.q, b.r);
  return {cx: cx2, cy: cy2, count: b.count};
});

const maxCount = Math.max(...hexData.map(b => b.count), 1);

transformedData = {hexData, maxCount, HEX_R};

echarts_js:
const {hexData, maxCount, HEX_R} = transformedData;

// 5-stop blue color ramp
const ramp = [
  [232, 244, 252],
  [158, 202, 225],
  [49,  130, 189],
  [8,   81,  156],
  [8,   48,  107]
];
const getColor = t => {
  if (t <= 0) return 'rgba(255,255,255,0)';
  const seg = t * (ramp.length - 1);
  const i = Math.min(Math.floor(seg), ramp.length - 2);
  const f = seg - i;
  const [r0,g0,b0] = ramp[i], [r1,g1,b1] = ramp[i+1];
  return `rgb(${Math.round(r0+(r1-r0)*f)},${Math.round(g0+(g1-g0)*f)},${Math.round(b0+(b1-b0)*f)})`;
};

const HEX_H = Math.sqrt(3) * HEX_R; // flat-top hex height in data coords

// Build a flat-top hexagon polygon path in data-coord offsets
const hexOffsets = Array.from({length:6}, (_,i) => [
  HEX_R * Math.cos(Math.PI/180 * (60*i)),
  HEX_R * Math.sin(Math.PI/180 * (60*i))
]);

const seriesData = hexData.map(b => ({
  value: [b.cx, b.cy, b.count],
  itemStyle: {
    color: getColor(b.count / maxCount),
    borderColor: '#8aafc8',
    borderWidth: 0.8
  }
}));

// Use custom series so hexagons are drawn in exact data-space coordinates
option = {
  backgroundColor: '#ffffff',
  title: {
    text: 'Hexbin Density Plot',
    left: 'center', top: 8,
    textStyle: {fontSize: 18, fontWeight: 'bold', color: '#1a1a2e'}
  },
  tooltip: {
    trigger: 'item',
    formatter: p => `<b>密度</b>: ${p.value[2]}<br/>X: ${Math.round(p.value[0])}, Y: ${Math.round(p.value[1])}`
  },
  visualMap: {
    min: 1, max: maxCount,
    calculable: true,
    orient: 'vertical',
    right: 16, top: 'center',
    inRange: {color: ['#e8f4fc','#9ecae1','#3182bd','#08519c','#08306b']},
    text: ['高密度','低密度'],
    textStyle: {color: '#444'}
  },
  grid: {left: 60, right: 110, top: 80, bottom: 50},
  xAxis: {type:'value', min: 0, max: 900, interval: 100, splitLine:{show:false}, axisLine:{lineStyle:{color:'#ccc'}}},
  yAxis: {type:'value', min: 0, max: 450, interval: 50, splitLine:{show:false}, axisLine:{lineStyle:{color:'#ccc'}}},
  series: [{
    type: 'custom',
    data: seriesData,
    encode: {x: 0, y: 1, tooltip: [0,1,2]},
    renderItem(params, api) {
      const [cx, cy] = [api.value(0), api.value(1)];
      const p0 = api.coord([cx + hexOffsets[0][0], cy + hexOffsets[0][1]]);
      const points2 = hexOffsets.map(([dx,dy]) => api.coord([cx+dx, cy+dy]));
      const style = api.style();
      return {
        type: 'polygon',
        shape: {points: points2},
        style
      };
    }
  }]
};
